css:
:root {
  --pri: #4c6ef5;
  --pri-light: #eef2ff;
  --pri-dark: #364fc7;
  --gold: #f59f00;
  --gold-pale: #fff9db;
  --red: #e03131;
  --green: #2f9e44;
  --bg: #f1f3f5;
  --card: #ffffff;
  --ink: #212529;
  --ink2: #495057;
  --ink3: #868e96;
  --border: #dee2e6;
  --shadow: 0 2px 12px rgba(0,0,0,.08);
  --shadow-lg: 0 8px 30px rgba(0,0,0,.12);
  --radius: 12px;
  --radius-sm: 8px;
}
* { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC",
               "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
  background: var(--bg);
  color: var(--ink);
  padding: 0;
  min-height: 100vh;
}

/* ── Banner ── */
.banner {
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 50%, #0f3460 100%);
  color: #fff; padding: 28px 24px 24px; text-align: center;
  position: relative; overflow: hidden;
}
.banner::before {
  content: ''; position: absolute; top: -50%; left: -50%;
  width: 200%; height: 200%;
  background: radial-gradient(circle, rgba(245,159,0,.1) 0%, transparent 50%);
  animation: pulse 4s ease-in-out infinite;
}
@keyframes pulse { 0%,100% { transform: scale(1); } 50% { transform: scale(1.05); } }
.banner h1 { font-size: 1.8rem; font-weight: 700; margin: 0; position: relative;
  letter-spacing: 2px; }
.banner .sub { color: var(--gold); font-size: .95rem; margin-top: 4px;
  position: relative; font-weight: 500; }
.banner .date-line { color: rgba(255,255,255,.6); font-size: .8rem; margin-top: 6px;
  position: relative; }
.banner .updated { position: absolute; bottom: 8px; right: 16px;
  font-size: .72rem; color: rgba(255,255,255,.4); }

/* ── Layout ── */
.container { max-width: 1400px; margin: 0 auto; padding: 16px; }

/* ── Tabs ── */
.tabs { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 14px; }
.tab {
  padding: 9px 18px; border: 2px solid var(--border); border-radius: var(--radius-sm);
  cursor: pointer; background: var(--card); font-size: .82rem; font-weight: 600;
  color: var(--ink2); transition: all .2s; box-shadow: var(--shadow);
}
.tab:hover { border-color: var(--pri); color: var(--pri); transform: translateY(-1px); }
.tab.active {
  background: var(--pri); color: #fff; border-color: var(--pri);
  box-shadow: 0 4px 12px rgba(76,110,245,.3);
}

/* ── Panels ── */
.panel { display: none }
.panel.active { display: block }

/* ── Filter ── */
.filter-bar { margin-bottom: 12px; font-size: .9rem; color: var(--ink2); display: flex; align-items: center; gap: 8px; flex-wrap: wrap; }
.filter-bar label { font-weight: 600; margin-right: 6px; }
.filter-bar select {
  padding: 7px 14px; border-radius: var(--radius-sm); border: 2px solid var(--border);
  font-size: .9rem; background: var(--card); color: var(--ink);
  transition: border-color .2s; outline: none;
}
.filter-bar select:focus { border-color: var(--pri); }


/* ── Stats ── */
.stats-row { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 16px; }
.stat {
  background: var(--card); border-radius: var(--radius-sm); padding: 14px 18px;
  flex: 1; min-width: 130px; text-align: center;
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  box-shadow: var(--shadow); transition: all .2s;
  border-left: 4px solid var(--pri);
}
.stat:nth-child(2) { border-left-color: var(--green); }
.stat:nth-child(3) { border-left-color: var(--gold); }
.stat:nth-child(4) { border-left-color: var(--red); }
.stat:nth-child(5) { border-left-color: #845ef7; }
.stat:hover { transform: translateY(-2px); box-shadow: var(--shadow-lg); }
.stat .num { font-size: 1.6rem; font-weight: 700; color: var(--ink);
  font-variant-numeric: tabular-nums; }
.stat .lbl { font-size: .82rem; color: var(--ink3); margin-top: 4px; font-weight: 500; }

/* ── Note ── */

.proj-name { font-weight: 700; font-size: .95rem; }


.note {
  background: linear-gradient(135deg, #fff9db 0%, #fff3bf 100%);
  border: 1px solid #ffd43b; border-radius: var(--radius-sm);
  padding: 10px 14px; margin-bottom: 12px; font-size: .82rem; line-height: 1.7;
}
.note b { color: #e67700; }

/* ── Table ── */
.tbl-wrap {
  max-height: 65vh; overflow-y: auto; border-radius: var(--radius);
  box-shadow: var(--shadow); background: var(--card);
}
.tbl-wrap::-webkit-scrollbar { width: 6px; }
.tbl-wrap::-webkit-scrollbar-thumb { background: #ced4da; border-radius: 3px; }
table { width: 100%; border-collapse: collapse; }
thead th {
  position: sticky; top: 0; z-index: 2;
  background: linear-gradient(135deg, var(--pri) 0%, var(--pri-dark) 100%);
  color: #fff; font-weight: 600; font-size: .75rem; padding: 10px 8px;
  text-align: center; letter-spacing: .3px; white-space: nowrap;
  border-bottom: 2px solid var(--pri-dark);
}
tbody td {
  font-size: .85rem; padding: 8px 10px; border-bottom: 1px solid #f1f3f5;
  white-space: nowrap; transition: background .15s;
}
tbody tr:nth-child(even) td { background: #f8f9fa; }
tbody tr:hover td { background: var(--pri-light); }
.num { text-align: right; font-variant-numeric: tabular-nums;
  font-family: "SF Mono", Menlo, "Cascadia Code", monospace; }

/* ── Status ── */
.arrear-yes { color: var(--red) !important; font-weight: 700; }
.dist-yes { color: var(--green); font-weight: 600; }
.dist-no { color: var(--red); font-weight: 600; }
.dist-partial { color: #e8590c; font-weight: 600; }

/* ── Tags ── */
.tag { display: inline-block; padding: 2px 8px; border-radius: 20px;
  font-size: .68rem; font-weight: 600; margin: 1px 2px; }
.tag-g { background: #d3f9d8; color: #2b8a3e; }
.tag-b { background: #d0ebff; color: #1864ab; }
.tag-o { background: #ffe8cc; color: #d9480f; }
.tag-r { background: #ffc9c9; color: #c92a2a; }
.tag-p { background: #e5dbff; color: #6741d9; }

/* ── Project groups ── */
.expand-btn {
  display: inline-block; margin-left: 8px; padding: 3px 10px;
  font-size: .72rem; cursor: pointer; border: 1.5px solid var(--gold);
  border-radius: 6px; background: transparent; color: var(--gold);
  transition: all .2s; font-weight: 600;
}

.proj-main-row { background: var(--gold-pale) !important; cursor: pointer; }
.proj-main-row:hover { background: #ffe5a0 !important; }
.proj-main-row td:first-child { font-weight: 700; font-size: .92rem; }


.sub-indent { padding-left: 28px !important; color: var(--pri); font-weight: 500; }
.hidden { display: none !important; }

/* ── 项目概览 cards ── */
.proj-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 10px; margin: 8px 0; }
.proj-card { background: var(--card); border-radius: var(--radius-sm); padding: 12px 14px;
  box-shadow: var(--shadow); border: 1px solid var(--border); transition: all .2s; }





/* ── 光伏看板 ── */
.solar-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 12px; }
.solar-card { background: var(--card); border-radius: var(--radius); padding: 16px;
  box-shadow: var(--shadow); border-top: 4px solid var(--gold); transition: all .2s; }
.solar-card:hover { transform: translateY(-3px); box-shadow: var(--shadow-lg); }
.solar-card h3 { font-size: .9rem; margin-bottom: 8px; }
.solar-card .num-big { font-size: 1.6rem; font-weight: 700; color: var(--pri);
  font-variant-numeric: tabular-nums; }
.solar-card .detail { font-size: .85rem; color: var(--ink2); line-height: 1.7; margin-top: 6px; }

.empty-state { padding: 40px; text-align: center; color: var(--ink3);
  font-size: .9rem; }

/* ── Banner legacy classes ── */
.banner-title { font-size: 1.8rem; font-weight: 700; letter-spacing: 2px; position: relative; }
.banner-title span { color: var(--gold); }
.banner-sub { color: rgba(255,255,255,.6); font-size: .8rem; margin-top: 4px; position: relative; }

/* ── Print ── */
@media print {
  .banner { background: #333 !important; -webkit-print-color-adjust: exact; }
  .tabs, .filter-bar, 
  .panel { display: block !important; }
  .tbl-wrap { max-height: none; overflow: visible; }
}
